mapper.select:
select YYYYMM, SEL_CODE, SITE as SITE_ORG, CASE WHEN SITE='HQ' then '본사' WHEN site='VN' then 'VINA' end as SITE, CASE WHEN ACCT_CLASS='AA' then '가공비' WHEN ACCT_CLASS='CC' then '판매관리비' WHEN ACCT_CLASS='BB' then '개발비' end as ACCT_CLASS, DEPT, ACCT, SUB_NAME, ITEM_NAME, ACCT_AMT, EXPEN_SEL from doi_acct_expen where 1=1
and yyyymm = #{yyyymm}
and site = #{site}
order BY DEPT;

DROP TABLE IF EXISTS #TempTable1;

CREATE TABLE #TempTable1 (
	YYYYMM varchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	SEL_CODE varchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	SITE varchar(4) COLLATE Korean_Wansung_CI_AS NULL,
	ACCT_CLASS varchar(4) COLLATE Korean_Wansung_CI_AS NULL,
	DEPT varchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	ACCT varchar(50) COLLATE Korean_Wansung_CI_AS NULL,
	SUB_NAME varchar(50) COLLATE Korean_Wansung_CI_AS NULL,
	ITEM_NAME varchar(50) COLLATE Korean_Wansung_CI_AS NULL,
	ACCT_AMT real NULL,
	EXPEN_SEL varchar(6) COLLATE Korean_Wansung_CI_AS NULL
);

INSERT INTO #TempTable1
(
YYYYMM
, SEL_CODE
, SITE
, SITE_ORG
, ACCT_CLASS
, DEPT
, ACCT
, SUB_NAME
, ITEM_NAME
, ACCT_AMT
, EXPEN_SEL
)
VALUES

	(
	#{item.field2}
