	)
;

SELECT * FROM #TempTable1 a
WHERE EXISTS (
	SELECT 1
	FROM DOI_ACCT_EXPEN b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SITE = a.SITE
	AND b.MODEL = a.MODEL
);

mapper.insert:
CREATE TABLE #TempTable (
	YYYYMM varchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	SEL_CODE varchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	SITE varchar(4) COLLATE Korean_Wansung_CI_AS NULL,
	ACCT_CLASS varchar(4) COLLATE Korean_Wansung_CI_AS NULL,
	DEPT varchar(10) COLLATE Korean_Wansung_CI_AS NULL,
	ACCT varchar(50) COLLATE Korean_Wansung_CI_AS NULL,
	SUB_NAME varchar(50) COLLATE Korean_Wansung_CI_AS NULL,
	ITEM_NAME varchar(50) COLLATE Korean_Wansung_CI_AS NULL,
	ACCT_AMT real NULL,
	EXPEN_SEL varchar(6) COLLATE Korean_Wansung_CI_AS NULL
);

INSERT INTO #TempTable
(
seq_no
, YYYYMM
, SEL_CODE
, SITE
, ACCT_CLASS
, DEPT
, ACCT
, SUB_NAME
, ITEM_NAME
, ACCT_AMT
, EXPEN_SEL
)
VALUES

	(
	#{item.field1}
	, #{item.field2}
	, #{item.field3}
	, #{item.field4}
	, #{item.field5}
	, #{item.field6}
	, #{item.field7}
	, #{item.field8}
	, #{item.field9}
	, #{item.field10}
	)
;

INSERT INTO DOI_ACCT_EXPEN (YYYYMM, SEL_CODE, SITE, ACCT_CLASS, DEPT, ACCT, SUB_NAME, ITEM_NAME, ACCT_AMT, EXPEN_SEL)
SELECT YYYYMM, SEL_CODE, SITE, ACCT_CLASS, DEPT, ACCT, SUB_NAME, ITEM_NAME, ACCT_AMT, EXPEN_SEL
FROM (
	SELECT *, MAX(seq_no) over (partition by YYYYMM, SITE, ACCT_CLASS, DEPT, ACCT) max_seq_no FROM #TempTable
) A
WHERE 1=1
AND seq_no = max_seq_no
AND NOT EXISTS (
	SELECT 1
	FROM DOI_ACCT_EXPEN b
	WHERE 1=1
	AND b.YYYYMM = a.YYYYMM
	AND b.SITE = a.SITE
	AND b.DEPT = a.DEPT
	AND b.ACCT = a.ACCT
);

DROP TABLE #TempTable;

INSERT INTO DOI_ACCT_EXPEN
(
YYYYMM
, SEL_CODE
, SITE
, ACCT_CLASS
, DEPT
, ACCT
, SUB_NAME
, ITEM_NAME
, ACCT_AMT
, EXPEN_SEL
)
VALUES
(
#{yyyymm}
, #{selCode}
, CASE WHEN #{site}='본사' Then 'HQ'  WHEN #{site}='베트남' then 'VN' else left(#{site},2) end
, #{acctClass}
, #{dept}
, #{acct}
, #{subName}
, #{itemName}
, #{acctAmt}
, #{expenSel}
);

mapper.delete:
